INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-00539', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '選擇適合配戴軟式隱形眼鏡的患者，下列敘述何者錯誤？', '["若眼前段檢查無眼疾及全身性的疾病，測試淚膜BUT平均值為15秒，則患者可配戴軟式隱形眼鏡", "有服用抗組織胺藥物（antihistamine）或有自體免疫（autoimmune）性疾病的患者，只適合配戴軟式隱形 眼鏡", "每周只間歇性配戴1~2次隱形眼鏡的運動員，適合配戴軟式隱形眼鏡", "角膜有中高度不規則散光者，可配戴球面硬式透氣隱形眼鏡（RGP）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00540', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關硬式隱形眼鏡驗配與螢光染劑，下列敘述何者錯誤？', '["建議請病人看下方，螢光染劑由上方結膜滴下", "螢光染色的分布型態，可以判斷角膜散光及軸性", "鏡片中心若有過多的螢光液堆積，代表鏡片弧度比角膜陡", "螢光染色區域若呈現有氣泡，表示鏡片接觸到角膜"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00541', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '隱形眼鏡的清潔方法有許多種類，使用下列何者之防腐劑相對無法進入軟式隱形眼鏡，使得其間接引起眼睛表', '["過氧化氫", "硫柳汞（thiomersal）", "polyhexanide", "polyquad"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00542', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '配戴弧度較緊的軟式散光鏡片容易出現的症狀，下列何者錯誤？', '["角膜新生血管", "角膜水腫", "角膜壓痕", "上邊緣性角膜結膜炎"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00543', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '角膜在低傳氧性狀態下時會引起的變化，包含下列何者？ ①造成角膜水腫  ②造成上皮細胞的多形性', '["產生內皮空泡（endothelialblebs）", "角膜PH值的改變  ⑤造成乳酸的堆積", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 36, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00544', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關角膜新生血管，下列何者錯誤？', '["隱形眼鏡過緊、鏡片壓迫輪狀部（limbus）或鏡片使用時間過長都是可能造成角膜新生血管的原因", "以同一種材質的隱形眼鏡來說，日戴（dailywear）的隱形眼鏡配戴者比長戴（extendedwear）的隱形眼 鏡配戴者容易產生角膜新生血管", "矽水膠材質（siliconehydrogel）的隱形眼鏡比起水膠材質（hydrogel）更不容易造成角膜新生血管", "角膜新生血管若在初期是可逆的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00545', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於軟式隱形眼鏡的沉澱物（deposits），下列何者錯誤？', '["主要可以分成有機（organic）還有無機（inorganic）兩種", "色素性沉澱物（pigmenteddeposit）主要的來源是淚液", "鏽斑（rustspot）的沉澱物和使用自來水清潔隱形眼鏡無關", "膠凍塊（jellybumps）是最常見的無機類沉澱物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00546', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '隱形眼鏡配戴所產生的角膜螢光點狀染色，其原因可能為下列何者？①機械性摩擦  ②毒性反應  ③角膜', '["過敏反應  ⑤感染", "僅", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 39, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00547', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '表面為非球面的軟式隱形眼鏡（中央光學區為視遠用，周圍區為近距離用、或中央光學區為視近用，周圍 區為遠距離用），較適合那一種老花眼患者？', '["老花眼初期（+1.25D或更低）", "高度近視眼", "有高階像差的重度老花眼（>+3.00D）", "有高度（>3.00D）散光的老花眼"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00548', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '對於硬式高透氣鏡片配戴者的清潔保存方式，下列何者錯誤？', '["配戴者應該使用廠商建議的清潔液", "經常配戴者，每天取下鏡片後，採取乾式保存比浸泡在清潔液中的保存方式更安全有效", "topping-off（未倒掉留置的舊保存液，只在保存盒內加滿新的保存液）是造成角膜感染的常見原因之一", "若長時間停止配戴，鏡片清洗後，應置入鏡片盒保存液中，但是留置時間以不超過30天為原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
